import json, sys, anthropic

client = anthropic.Anthropic()

EVAL_DATASET = [
    {
        "input": [{"role": "user", "content": "What is the capital of France?"}],
        "expected": "Paris",
    },
    {
        "input": [{"role": "user", "content": "Summarise the water cycle in one sentence."}],
        "rubric": "Must mention evaporation, condensation, and precipitation.",
    },
]

SYSTEM_PROMPT = "You are a helpful geography and science tutor."
THRESHOLD = 0.90  # 90% pass rate required


def run_agent(messages: list[dict]) -> str:
    resp = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=256,
        system=SYSTEM_PROMPT,
        messages=messages,
        temperature=0,
    )
    return resp.content[0].text


def judge(output: str, example: dict) -> bool:
    if "expected" in example:
        # Exact-ish match: ask judge whether output contains the expected answer
        rubric = f'The expected answer is: "{example["expected"]}". Does the response contain this information?'
    else:
        rubric = example["rubric"]

    verdict = client.messages.create(
        model="claude-haiku-4-5",
        max_tokens=8,
        messages=[
            {
                "role": "user",
                "content": (
                    f"Agent output:\n{output}\n\nCriterion: {rubric}\n"
                    "Reply with exactly YES or NO."
                ),
            }
        ],
        temperature=0,
    )
    return verdict.content[0].text.strip().upper().startswith("YES")


passed = 0
for i, example in enumerate(EVAL_DATASET):
    output = run_agent(example["input"])
    ok = judge(output, example)
    status = "PASS" if ok else "FAIL"
    print(f"[{i+1}/{len(EVAL_DATASET)}] {status}: {output[:80]}...")
    if ok:
        passed += 1

pass_rate = passed / len(EVAL_DATASET)
print(f"\nPass rate: {pass_rate:.1%} (threshold {THRESHOLD:.0%})")

if pass_rate < THRESHOLD:
    print("EVAL GATE FAILED — blocking merge")
    sys.exit(1)
else:
    print("EVAL GATE PASSED")
    sys.exit(0)

import anthropic, json

client = anthropic.Anthropic()

tools = [
    {
        "name": "search_flights",
        "description": "Search for available flights.",
        "input_schema": {
            "type": "object",
            "properties": {
                "origin": {"type": "string"},
                "destination": {"type": "string"},
                "date": {"type": "string", "description": "ISO 8601 date"},
            },
            "required": ["origin", "destination", "date"],
        },
    }
]

TOOL_EVALS = [
    {
        "input": "Find flights from NYC to London on 2025-03-15",
        "expected_tool": "search_flights",
        "expected_args": {"origin": "NYC", "destination": "London", "date": "2025-03-15"},
    }
]

passed = 0
for ex in TOOL_EVALS:
    resp = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=256,
        tools=tools,
        messages=[{"role": "user", "content": ex["input"]}],
        temperature=0,
    )
    # Extract tool use block
    tool_uses = [b for b in resp.content if b.type == "tool_use"]
    if not tool_uses:
        print(f"FAIL: no tool call made")
        continue
    call = tool_uses[0]
    if call.name == ex["expected_tool"] and call.input == ex["expected_args"]:
        passed += 1
        print(f"PASS: {call.name}({call.input})")
    else:
        print(f"FAIL: got {call.name}({call.input}), expected {ex['expected_tool']}({ex['expected_args']})")

print(f"Tool-call accuracy: {passed}/{len(TOOL_EVALS)}")
